def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            penalty = (ratio - 1) ** 2
            priorities[i] = penalty * 100
        elif ratio == 1:
            priorities[i] = 0
        else:
            log_ratio = np.log(capacity - item + 1)
            if log_ratio <= 0:
                priorities[i] = 50
            else:
                priorities[i] = 1 / log_ratio
        if capacity > 2 * item:
            priorities[i] += 0.5
    return priorities
